                bLin = (getNormPixel(x - 1.0, y - 1.0) + getNormPixel(x + 1.0, y - 1.0) + getNormPixel(x - 1.0, y + 1.0) + getNormPixel(x + 1.0, y + 1.0)) * 0.25;
